import type { ReactNode } from 'react';
/**
 * @public
 */
export interface FormFieldCustomMessage {
    /** Whether the message is a hint or an error. */
    variant: 'error' | 'hint';
    /** Unique identifier for the message to remove and update the messages. */
    id: string;
    /** Origin of the message, formcontrol means it is a browser or strato error and custom is an error set from outside. */
    messageType?: 'custom' | 'formcontrol';
    /** Unique identifier for the native input element connected to the error message. */
    controlId?: string;
}
/**
 * @public
 */
export interface FormFieldControlMessage extends FormFieldCustomMessage {
    message: ReactNode;
    validityStateKey: string;
}
/**
 * @internal
 */
export type FormFieldMessage = FormFieldCustomMessage | FormFieldControlMessage;
/**
 * @internal
 */
export interface FormFieldMessageContextState {
    formControlMessages: FormFieldControlMessage[];
    customMessages: FormFieldCustomMessage[];
    isTouched?: boolean;
    controlIds?: string[];
    isDisabled?: boolean;
    showError: boolean;
    isValid?: boolean;
}
